// Common UGameplayStatics usage

// Get player
ACharacter* Player = UGameplayStatics::GetPlayerCharacter(GetWorld(), 0);

// Apply damage
UGameplayStatics::ApplyDamage(TargetActor, 50.f, GetController(), this, UDamageType::StaticClass());

// Play sound
UGameplayStatics::PlaySoundAtLocation(this, FireSound, GetActorLocation());

// Spawn particles
UGameplayStatics::SpawnEmitterAtLocation(GetWorld(), ExplosionFX, HitLocation, HitRotation);

// Open level
UGameplayStatics::OpenLevel(GetWorld(), TEXT("MainMenu"));

// Slow motion
UGameplayStatics::SetGlobalTimeDilation(GetWorld(), 0.25f);

// Debug print
UKismetSystemLibrary::PrintString(GetWorld(), TEXT("Hello!"), true, true, FLinearColor::Green, 5.f);

// Traced line with debug visualization
FHitResult Hit;
bool bHit = UKismetSystemLibrary::LineTraceSingle(
    GetWorld(), Start, End,
    UEngineTypes::ConvertToTraceType(ECC_Visibility),
    false, TArray<AActor*>(), // Actors to ignore
    EDrawDebugTrace::ForDuration,
    Hit, true, // bIgnoreSelf
    FLinearColor::Red, FLinearColor::Green, 5.f
);

// Draw debug sphere
UKismetSystemLibrary::DrawDebugSphere(GetWorld(), Location, 50.f, 12, FLinearColor::Blue, 5.f);

// Clamp health
Health = FMath::Clamp(Health - Damage, 0.f, MaxHealth);

// Smooth camera follow (in Tick)
FVector NewLoc = FMath::VInterpTo(GetActorLocation(), TargetLocation, DeltaTime, 5.f);
SetActorLocation(NewLoc);

// Smooth rotation
FRotator NewRot = FMath::RInterpTo(GetActorRotation(), TargetRotation, DeltaTime, 10.f);
SetActorRotation(NewRot);

// Linear interpolation for UI
float HealthPercent = FMath::Lerp(0.f, 1.f, CurrentHealth / MaxHealth);

// Random
int32 RandomDamage = FMath::RandRange(10, 50);
float RandomAngle = FMath::RandRange(0.f, 360.f);

// Remap value from [0,100] to [0,1]
float Normalized = FMath::GetMappedRangeValueClamped(
    FVector2D(0.f, 100.f), FVector2D(0.f, 1.f), RawValue
);

// Direction to target
FVector Direction = (TargetLocation - GetActorLocation()).GetSafeNormal();
float Distance = FVector::Dist(GetActorLocation(), TargetLocation);

// Look at target
FRotator LookRot = FMath::FindLookAtRotation(GetActorLocation(), TargetLocation);
SetActorRotation(LookRot);

// Move forward
FVector Forward = GetActorForwardVector();
SetActorLocation(GetActorLocation() + Forward * Speed * DeltaTime);

// Dot product (facing check: > 0 means in front)
float Dot = FVector::DotProduct(GetActorForwardVector(), DirectionToTarget);
bool bInFront = Dot > 0.f;

// Cross product (perpendicular direction)
FVector Right = FVector::CrossProduct(FVector::UpVector, Forward);

// Safe casting pattern
void AMyActor::OnOverlap(AActor* OtherActor) {
    // Check validity first
    if (!IsValid(OtherActor)) return;

    // Try to cast
    if (AMyCharacter* Character = Cast<AMyCharacter>(OtherActor)) {
        Character->CollectPickup(this);
    }

    // Check without casting
    if (OtherActor->IsA<AProjectile>()) {
        Destroy();
    }
}

// Interface check
if (OtherActor->GetClass()->ImplementsInterface(UInteractable::StaticClass())) {
    IInteractable::Execute_Interact(OtherActor, this);
}

// Assertions (debug only)
check(MyComponent != nullptr);
ensure(Health >= 0.f);

// Find rotation to face target
FRotator LookAt = UKismetMathLibrary::FindLookAtRotation(
    GetActorLocation(), TargetActor->GetActorLocation()
);

// Get direction
FVector Dir = UKismetMathLibrary::GetDirectionUnitVector(
    GetActorLocation(), TargetActor->GetActorLocation()
);

// Random scatter
for (int i = 0; i < 5; i++) {
    FVector RandomDir = UKismetMathLibrary::RandomUnitVector();
    SpawnProjectile(RandomDir * 1000.f);
}

// Map range: convert 0-100 health to 0-1 for UI
float Percent = UKismetMathLibrary::MapRangeClamped(Health, 0.f, MaxHealth, 0.f, 1.f);
